{"path": "/tmp/sv-ad4e9f7109894e719017eaafffe45989/Components/Board/BoardSummaryBar.razor", "file_text": "<div class="summary-bar">
    <div class="summary-stat">
        <span class="stat-value">@Total</span>
        <span class="stat-label">Total</span>
    </div>
    <div class="summary-stat">
        <span class="stat-value">@TodoCount</span>
        <span class="stat-label">To Do</span>
    </div>
    <div class="summary-stat">
        <span class="stat-value">@InProgressCount</span>
        <span class="stat-label">In Progress</span>
    </div>
    <div class="summary-stat">
        <span class="stat-value">@DoneCount</span>
        <span class="stat-label">Done</span>
    </div>
    <div class="summary-stat summary-stat-overdue">
        <span class="stat-value">@OverdueCount</span>
        <span class="stat-label">Overdue</span>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = [];

    private int Total => Tasks.Count;
    private int TodoCount => Tasks.Count(t => t.Status == "To Do");
    private int InProgressCount => Tasks.Count(t => t.Status == "In Progress");
    private int DoneCount => Tasks.Count(t => t.Status == "Done");
    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today);
}
"}

{"path": "/tmp/sv-ad4e9f7109894e719017eaafffe45989/Components/Board/BoardSearchBar.razor", "file_text": "<div class="search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchTerm { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTermChanged.InvokeAsync(value);
    }
}
"}

{"path": "/tmp/sv-ad4e9f7109894e719017eaafffe45989/Components/Board/BoardColumn.razor", "file_text": "<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="@(ColumnIndex > 0)"
                      ShowMoveRight="@(ColumnIndex < 2)"
                      OnMoveLeftClicked="OnMoveLeftClicked"
                      OnMoveRightClicked="OnMoveRightClicked" />
        }
    </div>
    <div class="column-footer">
        <AddTaskForm OnSave="HandleAddTask" />
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    /// <summary>0 = To Do, 1 = In Progress, 2 = Done</summary>
    [Parameter]
    public int ColumnIndex { get; set; }

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = [];

    [Parameter]
    public EventCallback<(int TaskId, string Direction)> OnMoveTask { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private async Task OnMoveLeftClicked(int taskId)
        => await OnMoveTask.InvokeAsync((taskId, "left"));

    private async Task OnMoveRightClicked(int taskId)
        => await OnMoveTask.InvokeAsync((taskId, "right"));

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate) data)
        => await OnAddTask.InvokeAsync((data.Title, data.Assignee, data.Priority, data.DueDate, ColumnName));
}
"}

